import React, { useEffect, useState } from 'react';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import { useT, useLanguage } from '../context/LanguageContext';
import './Timetable.css';

const AP_COLORS = { CM: 'ap-cm', TD: 'ap-td', TP: 'ap-tp' };

export default function Timetable() {
  const { auth, apiHeaders } = useAuth();
  const t = useT();
  const { lang } = useLanguage();
  const ar = lang === 'ar';
  const [dias, setDias] = useState([]);
  const [selectedDia, setSelectedDia] = useState('');
  const [slots, setSlots] = useState([]);
  const [loading, setLoading] = useState(false);
  const [loadingDias, setLoadingDias] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!auth?.uuid) return;
    axios.get(`/api/student/dias/${auth.uuid}`, { headers: apiHeaders })
      .then(r => {
        const sorted = [...(r.data || [])].sort((a, b) => b.anneeAcademiqueId - a.anneeAcademiqueId);
        setDias(sorted);
        if (sorted.length > 0) setSelectedDia(sorted[0].id);
      })
      .catch(() => setError(t.timetable.errorLoad))
      .finally(() => setLoadingDias(false));
  }, [auth, apiHeaders]); // eslint-disable-line

  useEffect(() => {
    if (!selectedDia) return;
    setLoading(true);
    setError('');
    setSlots([]);
    axios.get(`/api/student/timetable/${selectedDia}`, { headers: apiHeaders })
      .then(r => setSlots(r.data || []))
      .catch(e => setError(e.response?.status === 404 ? t.timetable.noData : t.timetable.errorLoad))
      .finally(() => setLoading(false));
  }, [selectedDia, apiHeaders]); // eslint-disable-line

  // Group by day then sort by start time
  const byDay = slots.reduce((acc, s) => {
    const day = s.jourId || 0;
    if (!acc[day]) acc[day] = { label: ar ? s.jourLibelleAr : s.jourLibelleFr, slots: [] };
    acc[day].slots.push(s);
    return acc;
  }, {});
  Object.values(byDay).forEach(d => d.slots.sort((a, b) =>
    (a.plageHoraireHeureDebut || '').localeCompare(b.plageHoraireHeureDebut || '')
  ));
  const days = Object.entries(byDay).sort(([a], [b]) => Number(a) - Number(b));

  return (
    <div className="timetable-page">
      <div className="page-header">
        <div>
          <h1>{t.timetable.title}</h1>
          <p className="page-subtitle">{t.timetable.subtitle}</p>
        </div>
      </div>

      {!loadingDias && dias.length > 0 && (
        <div className="year-pills">
          {dias.map(d => (
            <button key={d.id} className={`year-pill ${selectedDia == d.id ? 'active' : ''}`}
              onClick={() => setSelectedDia(d.id)}>
              {d.anneeAcademiqueCode}
            </button>
          ))}
        </div>
      )}

      {loading && <div className="page-loader"><div className="spinner" /></div>}
      {error && <div className="error-banner">{error}</div>}

      {!loading && days.length > 0 && (
        <div className="tt-grid">
          {days.map(([dayId, day]) => (
            <div key={dayId} className="tt-day card">
              <div className="tt-day-header">{day.label || t.timetable.days[Number(dayId)] || dayId}</div>
              <div className="tt-slots">
                {day.slots.map((s, i) => (
                  <div key={i} className={`tt-slot ${AP_COLORS[s.ap] || 'ap-default'}`}>
                    <div className="tt-slot-time">
                      {s.plageHoraireLibelleFr || `${s.plageHoraireHeureDebut || ''}–${s.plageHoraireFin || ''}`}
                    </div>
                    <div className="tt-slot-body">
                      <div className="tt-slot-subject">{ar ? s.matiereAr : s.matiere}</div>
                      <div className="tt-slot-meta">
                        {s.ap && <span className={`ap-badge ${AP_COLORS[s.ap] || 'ap-default'}`}>{s.ap}</span>}
                        {s.refLieuDesignation && <span className="tt-room">{s.refLieuDesignation}</span>}
                      </div>
                      {(s.nomEnseignantLatin || s.nomEnseignantArabe) && (
                        <div className="tt-teacher">
                          {ar
                            ? `${s.prenomEnseignantArabe || ''} ${s.nomEnseignantArabe || ''}`
                            : `${s.prenomEnseignantLatin || ''} ${s.nomEnseignantLatin || ''}`}
                        </div>
                      )}
                    </div>
                  </div>
                ))}
              </div>
            </div>
          ))}
        </div>
      )}

      {!loading && !error && days.length === 0 && selectedDia && (
        <div className="empty-state">
          <svg width="48" height="48" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="1.5"><rect x="3" y="4" width="18" height="18" rx="2"/><line x1="16" y1="2" x2="16" y2="6"/><line x1="8" y1="2" x2="8" y2="6"/><line x1="3" y1="10" x2="21" y2="10"/></svg>
          <p>{t.timetable.noData}</p>
        </div>
      )}
    </div>
  );
}
